logger = logging.getLogger(__name__)


class OperatingProcedure(str, Enum):
    """Classification of query types"""
    QA = "q-and-a"
    FACT_FINDING = "fact-finding"
    OTHER = "other"


class WorkflowAgent:
    """
    Multi-stage agent workflow for SPIC MACAY queries
    Using OpenAI GPT models
    """
    
    def __init__(self, api_key: str, knowledge_base: Optional[Dict] = None):
        """
        Initialize workflow with OpenAI
        
        Args:
            api_key: OpenAI API key
            knowledge_base: SPIC MACAY knowledge base
        """
        self.client = OpenAI(api_key=api_key)
        self.knowledge_base = knowledge_base or self._load_default_knowledge()
        self.conversation_history = []
        logger.info("OpenAI Workflow Agent initialized")
    
