    def _search_knowledge_base(self, query: str) -> Dict:
        """Search knowledge base for relevant information"""
        query_lower = query.lower()
        relevant = {}
        
        # Search about section
        if any(word in query_lower for word in ['about', 'what is', 'founded', 'mission', 'history']):
            relevant['about'] = self.knowledge_base.get('about', {})
        
        # Search programs
        if any(word in query_lower for word in ['program', 'event', 'anubhav', 'virasat', 'lecture', 'concert']):
            relevant['programs'] = self.knowledge_base.get('programs', [])
        
        # Search art forms
        if any(word in query_lower for word in ['art', 'music', 'dance', 'classical']):
            relevant['art_forms'] = self.knowledge_base.get('art_forms', [])
        
        # Search contact
        if any(word in query_lower for word in ['contact', 'email', 'website', 'reach']):
            relevant['contact'] = self.knowledge_base.get('contact', {})
        
        # If nothing specific, return everything
        if not relevant:
            relevant = self.knowledge_base
        
        return relevant
